```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>
#include <type_traits>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database and insert the records.
  // Note: sqlgen infers the table schema from the type T, so table_name is not strictly needed
  // for the insert_into call, but we keep the signature as requested.
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        return sqlgen::insert_into(conn, records);
      })
      .value();
}

// Helper function to format values for SQL queries
template <typename T>
std::string _eas_to_sql_val(const T& val) {
  if constexpr (std::is_arithmetic_v<T>) {
    return std::to_string(val);
  } else {
    return "'" + std::string(val) + "'";
  }
}

template <typename IdT, typename ValT>
void modify_eas_records_by_id(const std::string& table_name,
                              const IdT& record_id,
                              const std::string& col_name,
                              const ValT& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Convert record_id to string for query construction
  std::string id_str;
  if constexpr (std::is_arithmetic_v<IdT>) {
    id_str = std::to_string(record_id);
  } else {
    id_str = std::string(record_id);
  }

  // Determine the WHERE clause based on the table's primary key
  std::string where_clause;
  if (table_name == "Student") {
    // Student PK is SNo (Varchar), needs quotes
    where_clause = "SNo = '" + id_str + "'";
  } else if (table_name == "Course") {
    // Course PK is CID (int)
    where_clause = "CID = " + id_str;
  } else if (table_name == "Score") {
    // Score PK is ScID (int)
    where_clause = "ScID = " + id_str;
  } else if (table_name == "Major") {
    // Major PK is MID (int)
    where_clause = "MID = " + id_str;
  }

  // Construct and execute the raw SQL update
  std::string sql = "UPDATE " + table_name + " SET " + col_name + " = " +
                    _eas_to_sql_val(new_value) + " WHERE " + where_clause + ";";

  sqlgen::exec(conn, sql);
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  std::string where_clause;
  if (table_name == "Student") {
    where_clause = "SNo = '" + record_id + "'";
  } else if (table_name == "Course") {
    where_clause = "CID = " + record_id;
  } else if (table_name == "Score") {
    where_clause = "ScID = " + record_id;
  } else if (table_name == "Major") {
    where_clause = "MID = " + record_id;
  }

  std::string sql = "DELETE FROM " + table_name + " WHERE " + where_clause + ";";
  sqlgen::exec(conn, sql);
}
