 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
   try {
       // 1. Connect to the SQLite database "test_db.sqlite"
       auto db = sqlgen::sqlite::connect("test_db.sqlite");

       // 2. Drop the table if it exists to ensure a clean state
       // We use raw SQL here to ensure the "IF EXISTS" clause is handled correctly
       db.execute("DROP TABLE IF EXISTS Product");

       // 3. Create the Product table based on the struct definition
       db.create_table<Product>();

       // 4. Begin a transaction
