    // Scorses: float, NULL DEFAULT 0
    rfl::Rename<"Scorses", std::optional<float>> scorses;

    // Remark: text, NULL
    rfl::Rename<"Remark", std::optional<std::string>> remark;
  };

  struct Course {
    // CID: int, NOT NULL auto_increment PK
    // In SQLite, INTEGER PRIMARY KEY is auto-increment by default
    rfl::Rename<"CID", sqlgen::PrimaryKey<int>> cid;

    // CName: varchar(30), NOT NULL
