    // Connect to the SQLite database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Create tables. 
    // Note: Tables referenced by Foreign Keys (Student, Course) must be created 
    // before the table containing the Foreign Keys (Score).
    db.create_table<Student>();
    db.create_table<Course>();
    db.create_table<Score>();
  }

}
