std::vector<OrderView> query_high_value_orders() {
  using namespace sqlgen;
  using namespace sqlgen::literals;
  auto conn = sqlite::connect("test_db.sqlite");
  if (!conn) return {};
  create_table<Customer>(conn);
  create_table<Order>(conn);

  const auto query = 
      select_from<Order, "t1">(
          "order_id"_t1 | as<"order_id">,
          "name"_t2 | as<"name">,
          "total_amount"_t1 | as<"total_amount">,
          "order_date"_t1 | as<"order_date">) |
      inner_join<Customer, "t2">("customer_id"_t1 == "customer_id"_t2) |
      where("total_amount"_t1 > 1000.0) |
      order_by("total_amount"_t1.desc());

  const auto create_view = create_as<OrderView>(query) | if_not_exists;
  create_view(conn);

  return sqlgen::read<std::vector<OrderView>>(conn).value();
}

}  // namespace query_high_value_orders

