```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <exception>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  try {
    // 1. Connect to the SQLite database
    sqlgen::SQLite db("test_db.sqlite");

    // 2. Start a transaction
    db.execute("BEGIN TRANSACTION");

    // 3 & 4. Check funds and Deduct from sender
    // We use an atomic update to ensure the balance is sufficient at the exact moment of deduction.
    // The query returns the number of affected rows.
    int rows_deducted = db.execute(
        "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?", 
        amount, from_account_id, amount
    );

    // If 0 rows were affected, it means either the account doesn't exist 
    // or the balance was insufficient.
    if (rows_deducted == 0) {
      db.execute("ROLLBACK");
      return false;
    }

    // 5. Add to receiver
    int rows_added = db.execute(
        "UPDATE Account SET balance = balance + ? WHERE account_id = ?", 
        amount, to_account_id
    );

    // If 0 rows were affected, the receiver account ID is invalid.
    if (rows_added == 0) {
      db.execute("ROLLBACK");
      return false;
    }

    // 6. Commit if successful
    db.execute("COMMIT");
    return true;

  } catch (const std::exception& e) {
    // In case of any SQL errors or connection issues, we attempt to rollback (if possible)
    // and return false indicating failure.
    try {
      sqlgen::SQLite db("test_db.sqlite");
      db.execute("ROLLBACK");
    } catch (...) {
      // Ignore errors during rollback in catch block
    }
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

