Here is the complete content of the file `update_eas_table.hpp`.

The implementation uses `sqlgen::exec` to perform the Data Definition Language (DDL) operations required. Note that for SQLite, adding a `NOT NULL` column (Task 1) requires a default value. Also, since the `Student` table defined in `eas_common.hpp` does not initially contain an `Age` column, Task 2 is implemented as adding the column `Age` with the specified type.

```cpp
// update_eas_table.hpp
#pragma once

#include <filesystem>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

#include "eas_common.hpp"

namespace update_eas_table {

void update_eas_table() {
  // Ensure the database is in the initial state with Major table
  design_eas_database_with_major();

  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add a new column Grade to the table Score, with type char(1), not allowing null values.
        // SQLite requires a DEFAULT value when adding a NOT NULL column to an existing table.
        return sqlgen::exec(conn, "ALTER TABLE Score ADD COLUMN Grade char(1) NOT NULL DEFAULT 'A';");
      })
      .and_then([](auto&& conn) {
        // 2. Modify the column type of Age in the table Student to int, allowing null values.
        // Since the initial Student table (from eas_common.hpp) does not have an Age column,
        // we interpret "Modify" as ensuring the column exists with the correct type.
        // SQLite supports ADD COLUMN.
        return sqlgen::exec(conn, "ALTER TABLE Student ADD COLUMN Age int;");
