 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  try {
    // 1. Connect to the SQLite database
    sqlgen::sqlite::Database db("test_db.sqlite");

    // 2. Handle "DROP IF EXISTS" manually
    // SQLite does not support "CREATE OR REPLACE VIEW", so we drop it first to ensure
    // the definition is updated.
    db.execute("DROP VIEW IF EXISTS SalesSummary;");

    // 3. Construct the SELECT query for the view
    // Corresponds to:
    // SELECT p.name as product_name, SUM(s.quantity) as total_quantity, SUM(s.amount) as total_revenue
    // FROM Sale s JOIN Product p ON s.product_id = p.product_id
