  // 1. Connect to the SQLite database helpers
  sqlgen::SQLite db("test_db.sqlite");

  // 2. Define table proxies for query construction
  auto a = sqlgen::table<A>("A");
  auto b = sqlgen::table<B>("B");

  // 3. Build the complex query
  // Requirements: Join, Where, Order By, Limit
  auto query = sqlgen::select(a.id, a.name, b.score)
                   .from(a)
                   .join(b, a.id == b.a_id)                     // Join A and B
                   .where(b.score > 10 && a.name.like("%x%"))   // Filter: score > 10 AND name contains 'x'
                   .order_by(b.score, sqlgen::desc)             // Order by score descending
                   .limit(50);                                  // Limit results

  // 4. Generate SQL string for SQLite without execution (Dry Run)
  return query.to_sql();
}

}  // namespace generate_sql_dry_run
