  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

// Updated Friendship struct to match the Table Description
struct Friendship {
  int user_id1; // Foreign Key to User
  int user_id2; // Foreign Key to User
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;

