/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection> representing Friend-of-Friend relationships.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    // 1. Connect to the database
    sqlgen::SQLite db("test_db.sqlite");

    // 2. Create Tables
    // We drop tables if they exist to ensure a clean state for analysis
    db.execute("DROP TABLE IF EXISTS Friendship;");
    db.execute("DROP TABLE IF EXISTS User;");

    // Define table schemas
    auto user_table = sqlgen::Table<User>("User", 
        sqlgen::Column("user_id", &User::user_id),
        sqlgen::Column("username", &User::username),
        sqlgen::Column("email", &User::email),
        sqlgen::Column("join_date", &User::join_date),
        sqlgen::Column("city", &User::city)
    );

    auto friendship_table = sqlgen::Table<Friendship>("Friendship",
        sqlgen::Column("user_id1", &Friendship::user_id1),
        sqlgen::Column("user_id2", &Friendship::user_id2),
        sqlgen::Column("friendship_date", &Friendship::friendship_date),
        sqlgen::Constraint("PRIMARY KEY (user_id1, user_id2)"),
        sqlgen::Constraint("FOREIGN KEY (user_id1) REFERENCES User(user_id)"),
        sqlgen::Constraint("FOREIGN KEY (user_id2) REFERENCES User(user_id)")
    );

    db.execute(user_table.create());
    db.execute(friendship_table.create());

    // 3. Insert Data
    // Assuming sqlgen supports batch insert or iterating to insert
    for (const auto& user : users) {
        db.execute(user_table.insert(user));
    }

    // Insert friendships (ensure bidirectional if the logic requires it, 
    // though the prompt implies directed or explicit pairs. 
    // Usually social networks store A->B and B->A, or queries handle A<B).
    for (const auto& fs : friendships) {
        db.execute(friendship_table.insert(fs));
    }

    // 4. Perform Analysis Queries

    // Task A: Use Nested Query to find users with more than average friends
    // This identifies "Influencers" or highly connected users.
    std::string popular_users_sql = R"(
        SELECT u.username 
        FROM User u
        JOIN Friendship f ON u.user_id = f.user_id1
        GROUP BY u.user_id, u.username
        HAVING COUNT(f.user_id2) > (
            SELECT AVG(friend_count) 
            FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1)
        );
    )";
    // We execute this for analysis purposes (results could be logged)
    db.execute(popular_users_sql);

    // Task B: Find users in the same city who are not yet friends (Recommendation)
    std::string city_recommendation_sql = R"(
        SELECT u1.username, u2.username
        FROM User u1
        JOIN User u2 ON u1.city = u2.city
        WHERE u1.user_id < u2.user_id
          AND NOT EXISTS (
            SELECT 1 FROM Friendship f 
            WHERE f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id
