#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  // 1. Connect to the database
  sqlgen::SQLite db("test_db.sqlite");

  // 2. Initialize the table (Drop if exists to ensure clean state, then create)
  db.drop_table<OrderItem>();
  db.create_table<OrderItem>();

  // 3. Insert the input data
  db.insert(items);

  // 4. Define the schema alias for query construction
  auto s = sqlgen::of<OrderItem>("OrderItem");

  // 5. Define reusable SQL expressions for calculations
  // Handle NULLs for rates using COALESCE
  auto discount_val = sqlgen::coalesce(s.discount_rate, 0.0);
  auto tax_val = sqlgen::coalesce(s.tax_rate, 0.0);

  // Arithmetic: Multiplication for Gross Total
  auto gross_total_expr = s.unit_price * s.quantity;

  // Arithmetic: Subtraction and Division for Discount Factor (1 - rate/100)
  auto discount_factor = 1.0 - (discount_val / 100.0);

  // Arithmetic: Addition and Division for Tax Factor (1 + rate/100)
  auto tax_factor = 1.0 + (tax_val / 100.0);

  // Complex Arithmetic: Chained multiplication
  auto discounted_total_expr = gross_total_expr * discount_factor;
  auto final_total_expr = discounted_total_expr * tax_factor;

  // Arithmetic: Division (Total / Quantity)
  auto unit_cost_expr = (s.unit_price * s.quantity) / s.quantity;

  // Arithmetic: Modulo for grouping
  auto quantity_group_expr = s.quantity % 10;

  // Arithmetic: Multiplication for profit estimation
  auto estimated_profit_expr = s.unit_price * 0.3;

  // 6. Execute the query
  // We select the raw columns and the calculated expressions
  auto rows = db.select(
      s.item_id,
      s.order_id,
      s.product_id,
      s.unit_price,
      s.quantity,
      discount_val,         // Return the coalesced value for the metric struct
      tax_val,              // Return the coalesced value for the metric struct
      gross_total_expr,
      discounted_total_expr,
      final_total_expr,
      unit_cost_expr,
      quantity_group_expr,
      estimated_profit_expr
  ).from(s).all();

  // 7. Map results to OrderMetrics vector
  std::vector<OrderMetrics> metrics;
  metrics.reserve(rows.size());

  for (const auto& row : rows) {
    metrics.push_back({
        std::get<0>(row),  // item_id
        std::get<1>(row),  // order_id
        std::get<2>(row),  // product_id
        std::get<3>(row),  // unit_price
        std::get<4>(row),  // quantity
        std::get<5>(row),  // discount_rate (coalesced)
        std::get<6>(row),  // tax_rate (coalesced)
        std::get<7>(row),  // gross_total
        std::get<8>(row),  // discounted_total
        std::get<9>(row),  // final_total
        std::get<10>(row), // unit_cost
        std::get<11>(row), // quantity_group
        std::get<12>(row)  // estimated_profit
    });
  }

  return metrics;
}

}  // namespace calculate_order_metrics
