Here is the complete content of the file, implementing the `cascade_delete_demo` function.

The implementation ensures that SQLite Foreign Key support is enabled (which is disabled by default in SQLite) and creates the tables with the specific `ON DELETE CASCADE` constraint required for the demonstration.

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  try {
    // 1. Connect to the SQLite database
    sqlgen::SQLite db("test_db.sqlite");

    // 2. Enable Foreign Keys
    // SQLite has foreign keys disabled by default. They must be enabled for CASCADE to work.
    db.execute("PRAGMA foreign_keys = ON;");

    // 3. Clean up previous runs (Drop Child first because it depends on Parent)
    db.execute("DROP TABLE IF EXISTS Child;");
    db.execute("DROP TABLE IF EXISTS Parent;");

    // 4. Create Tables
    // We create the Parent table using the ORM's standard method.
    db.create_table<Parent>();

    // We create the Child table using Raw SQL.
    // This is necessary to explicitly define "ON DELETE CASCADE", as standard
    // struct-based table generation might not apply this specific constraint by default.
    db.execute(
        "CREATE TABLE Child ("
        "child_id INTEGER PRIMARY KEY, "
        "parent_id INTEGER, "
        "note TEXT, "
        "FOREIGN KEY(parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE"
        ");");

    // 5. Insert parent and child records
    Parent p;
    p.parent_id = 1;
    p.name = "Target Parent";
    db.insert(p);

    Child c;
    c.child_id = 101;
    c.parent_id = 1;
    c.note = "Target Child";
    db.insert(c);

    // Sanity check: Ensure child actually exists before deletion
    auto check_insert = db.select<Child>("WHERE parent_id = 1");
    if (check_insert.empty()) {
      return false; // Setup failed
    }

    // 6. Delete Parent
    // Because of ON DELETE CASCADE, this should automatically remove the Child record.
    db.remove(p);

    // 7. Verify whether child rows are deleted automatically
    auto check_delete = db.select<Child>("WHERE parent_id = 1");

    // 8. Return verification result
    // If the vector is empty, the child was successfully deleted via cascade.
    return check_delete.empty();

  } catch (const std::exception& e) {
    // If an error occurs (connection fail, constraint violation, etc.), return false
    return false;
  }
}

}  // namespace cascade_delete_demo
