#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <iostream>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  try {
    // Connect to the database
    sqlgen::SQLite db("test_db.sqlite");

    // 1. Create Account table (drop if exists to ensure clean state)
    db.dropTable<Account>();
    db.createTable<Account>();

    // Insert initial data to operate on
    Account initial_account{1, 1000.0, "pending"};
    db.insert(initial_account);

    // 2. Update balances and statuses using set(...)
    // We update account 1: change balance to 2500.50 and status to "active"
    db.update<Account>()
        .set(&Account::balance, 2500.50)
        .set(&Account::status, "active")
        .where(sqlgen::eq(&Account::account_id, 1))
        .execute();

    // 3. Verify changes persisted
    auto result = db.query<Account>()
                    .where(sqlgen::eq(&Account::account_id, 1))
                    .findFirst();

    if (!result) {
      std::cerr << "Error: Account not found after update." << std::endl;
      return false;
    }

    // Check if values match the updates
    bool balance_ok = (result->balance == 2500.50);
    bool status_ok = (result->status == "active");

    if (balance_ok && status_ok) {
      return true;
    } else {
      std::cerr << "Error: Verification failed. Balance: " << result->balance 
                << ", Status: " << result->status << std::endl;
      return false;
    }

  } catch (const std::exception& e) {
    std::cerr << "Exception occurred: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace update_set_operations
