```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <algorithm>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  JoinAnalysis analysis;

  // 1. Connect to the database
  sqlgen::SQLite db("test_db.sqlite");

  // 2. Reset and Initialize Tables
  // We drop existing tables to ensure a clean state for the analysis
  db.execute("DROP TABLE IF EXISTS Employee");
  db.execute("DROP TABLE IF EXISTS Department");

  db.createTable<Department>();
  db.createTable<Employee>();

  // 3. Insert Data
  // Assuming sqlgen supports bulk insertion or iterating through vectors
  for (const auto& dept : depts) {
    db.insert(dept);
  }
  for (const auto& emp : emps) {
    db.insert(emp);
  }

  // 4. Perform INNER JOIN
  // Get employees with assigned departments
  // SQL: SELECT d.department_name, e.first_name, e.last_name, e.salary 
  //      FROM Department d INNER JOIN Employee e ON d.department_id = e.department_id
  analysis.inner_join_results = db.select<JoinResult>(
          "d.department_name", "e.first_name", "e.last_name", "e.salary")
      .from<Department>("d")
      .inner_join<Employee>("e", "d.department_id = e.department_id")
      .all();

  // 5. Perform LEFT JOIN
  // Include all employees (even without departments)
  // SQL: SELECT d.department_name, e.first_name, e.last_name, e.salary 
  //      FROM Employee e LEFT JOIN Department d ON e.department_id = d.department_id
  analysis.left_join_results = db.select<JoinResult>(
          "d.department_name", "e.first_name", "e.last_name", "e.salary")
      .from<Employee>("e")
      .left_join<Department>("d", "e.department_id = d.department_id")
      .all();

  // 6. Perform RIGHT JOIN
  // Include all departments (even without employees)
  // Note: SQLite does not support RIGHT JOIN natively. We simulate it by swapping the tables
  // and performing a LEFT JOIN (Department LEFT JOIN Employee).
  // SQL Equivalent: SELECT d.department_name, e.first_name, e.last_name, e.salary 
  //                 FROM Department d LEFT JOIN Employee e ON d.department_id = e.department_id
  analysis.right_join_results = db.select<JoinResult>(
          "d.department_name", "e.first_name", "e.last_name", "e.salary")
      .from<Department>("d")
      .left_join<Employee>("e", "d.department_id = e.department_id")
      .all();

  // 7. Perform FULL JOIN
  // Include all employees and departments.
  // Note: SQLite does not support FULL OUTER JOIN. 
  // Logic: FULL JOIN = (Left Join Results) UNION (Right Join Results where Left side is NULL).

  // Start with all results from the Left Join (All Employees)
  analysis.full_join_results = analysis.left_join_results;

  // Add results from the Right Join (All Departments) that were not matched in the Left Join.
  // In the 'right_join_results' (which is Dept LEFT JOIN Emp), unmatched rows have NULL employee fields.
  for (const auto& row : analysis.right_join_results) {
    // If first_name is null (or empty depending on mapping), it means this Department has no Employee.
    // This row represents the "Right Only" part of the Venn diagram.
    if (!row.first_name.has_value()) {
      analysis.full_join_results.push_back(row);
    }
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

