Here is the complete content of the file with the implemented function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
  return sqlgen::create_table<Target>().as(
      sqlgen::select<Source>().where(sqlgen::column<Source>("value") > 100));
}

}  // namespace create_table_as_select
```

